import React, { useState, useEffect } from "react";
import { Button, Table, Modal, Form } from "react-bootstrap";

const API_URL = "http://127.0.0.1:8000";

export default function InvoiceExtractor() {
  const [file, setFile] = useState(null);
  const [invoices, setInvoices] = useState([]);
  const [editingInvoice, setEditingInvoice] = useState(null);

  useEffect(() => {
    fetchInvoices();
  }, []);

  const handleFileUpload = (event) => {
    setFile(event.target.files[0]);
  };

  const uploadInvoice = async () => {
    if (!file) return;
    const formData = new FormData();
    formData.append("file", file);

    const response = await fetch(`${API_URL}/upload/`, {
      method: "POST",
      body: formData,
    });
    if (response.ok) {
      fetchInvoices();
    }
  };

  const fetchInvoices = async () => {
    const response = await fetch(`${API_URL}/invoices/`);
    const data = await response.json();
    setInvoices(data.invoices);
  };

  const deleteInvoice = async (id) => {
    await fetch(`${API_URL}/delete/${id}`, { method: "DELETE" });
    fetchInvoices();
  };

  const handleEdit = (invoice) => {
    setEditingInvoice(invoice);
  };

  const handleEditChange = (e) => {
    setEditingInvoice({ ...editingInvoice, [e.target.name]: e.target.value });
  };

  const saveEdit = async () => {
    await fetch(`${API_URL}/update/${editingInvoice.id}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(editingInvoice),
    });
    setEditingInvoice(null);
    fetchInvoices();
  };

  return (
    <div className="p-4">
      <h1 className="text-2xl font-bold mb-4">Invoice Extractor</h1>
      <div className="flex flex-col space-y-2 mb-4">
        <label className="font-semibold">Upload Invoice File:</label>
        <input type="file" onChange={handleFileUpload} className="p-2 border rounded" />
        <Button onClick={uploadInvoice} className="p-2 bg-blue-500 text-white rounded">Upload Invoice</Button>
      </div>
      
      <Table striped bordered hover className="table-auto w-full text-left">
        <thead>
          <tr>
            <th className="p-3">ID</th>
            <th className="p-3">Filename</th>
            <th className="p-3">Amount</th>
            <th className="p-3">Date</th>
            <th className="p-3">Order #</th>
            <th className="p-3">Merchant</th>
            <th className="p-3">Actions</th>
          </tr>
        </thead>
        <tbody>
          {invoices.length > 0 ? (
            invoices.map((invoice) => (
              <tr key={invoice.id}>
                <td className="p-3">{invoice.id}</td>
                <td className="p-3">{invoice.filename}</td>
                <td className="p-3">${invoice.amount}</td>
                <td className="p-3">{invoice.date}</td>
                <td className="p-3">{invoice.order_number}</td>
                <td className="p-3">{invoice.merchant}</td>
                <td className="p-3">
                  <Button className="mr-2 bg-red-500 text-white p-1 rounded" onClick={() => deleteInvoice(invoice.id)}>Delete</Button>
                  <Button className="bg-green-500 text-white p-1 rounded" onClick={() => handleEdit(invoice)}>Edit</Button>
                  <a href={`${API_URL}/download/${encodeURIComponent(invoice.filename)}`} className="ml-2 bg-blue-500 text-white p-1 rounded" download>Download</a>
                  <a href={`${API_URL}/view/${encodeURIComponent(invoice.filename)}`} target="_blank" rel="noopener noreferrer" className="ml-2 bg-gray-500 text-white p-1 rounded">View</a>
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="7" className="text-center p-3">No invoices found</td>
            </tr>
          )}
        </tbody>
      </Table>
      
      {editingInvoice && (
        <Modal show={true} onHide={() => setEditingInvoice(null)}>
          <Modal.Header closeButton>
            <Modal.Title>Edit Invoice</Modal.Title>
          </Modal.Header>
          <Modal.Body>
            <Form>
              <Form.Group>
                <Form.Label>Amount</Form.Label>
                <Form.Control type="text" name="amount" value={editingInvoice.amount} onChange={handleEditChange} />
              </Form.Group>
              <Form.Group>
                <Form.Label>Date</Form.Label>
                <Form.Control type="date" name="date" value={editingInvoice.date} onChange={handleEditChange} />
              </Form.Group>
              <Form.Group>
                <Form.Label>Order #</Form.Label>
                <Form.Control type="text" name="order_number" value={editingInvoice.order_number} onChange={handleEditChange} />
              </Form.Group>
              <Form.Group>
                <Form.Label>Merchant</Form.Label>
                <Form.Control type="text" name="merchant" value={editingInvoice.merchant} onChange={handleEditChange} />
              </Form.Group>
            </Form>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="secondary" onClick={() => setEditingInvoice(null)}>Close</Button>
            <Button variant="primary" onClick={saveEdit}>Save Changes</Button>
          </Modal.Footer>
        </Modal>
      )}
    </div>
  );
}
